function ShapeSelector({ current, onSelect }) {
  const shapes = ['box', 'sphere', 'torus', 'knot'];
  return (
    <div className="flex gap-2">
      {shapes.map(s => (
        <button
          key={s}
          onClick={() => onSelect(s)}
          className={`px-3 py-1.5 rounded-md text-xs transition-colors ${
            current === s
              ? 'bg-cyan-600 text-white'
              : 'bg-zinc-800 text-zinc-400 hover:text-zinc-200'
          }`}
        >{s}</button>
      ))}
    </div>
  );
}

function StatusBar({ params, onShapeSelect }) {
  return (
    <div className="px-6 py-4 bg-zinc-900/50 border-t border-zinc-800/50 flex items-center gap-6 flex-wrap">
      <ShapeSelector current={params.shape} onSelect={onShapeSelect} />
      <Stat label="Speed">
        <span className="text-sm font-mono text-cyan-400">{params.rotSpeed}x</span>
      </Stat>
      <Stat label="Scale">
        <span className="text-sm font-mono text-cyan-400">{params.scale}x</span>
      </Stat>
      <Stat label="Color">
        <span className="w-4 h-4 rounded-full border border-zinc-700" style={{backgroundColor: params.color}} />
      </Stat>
    </div>
  );
}

import { Scene, PerspectiveCamera, WebGLRenderer, AmbientLight, PointLight, MeshStandardMaterial, Mesh, Timer, BoxGeometry, SphereGeometry, TorusGeometry, TorusKnotGeometry } from 'three';

function ThreeCanvas({ params }) {
  const mountRef = useRef(null);
  const stateRef = useRef(null);

  useEffect(() => {
    const el = mountRef.current;
    const w = el.clientWidth;
    const h = el.clientHeight;

    const scene = new Scene();
    const camera = new PerspectiveCamera(50, w / h, 0.1, 100);
    camera.position.z = 4;

    const renderer = new WebGLRenderer({ antialias: true, alpha: true });
    renderer.setSize(w, h);
    renderer.setPixelRatio(window.devicePixelRatio);
    el.appendChild(renderer.domElement);

    scene.add(new AmbientLight(0xffffff, 0.4));
    const point = new PointLight(0xffffff, 1.2, 100);
    point.position.set(5, 5, 5);
    scene.add(point);

    const mat = new MeshStandardMaterial({ color: 0x22d3ee, roughness: 0.3, metalness: 0.7 });
    const geo = new TorusKnotGeometry(1, 0.35, 100, 16);
    const mesh = new Mesh(geo, mat);
    scene.add(mesh);

    const timer = new Timer();
    const st = { mesh, scene, camera, renderer, timer, speed: 1 };
    stateRef.current = st;

    let raf;
    function animate() {
      raf = requestAnimationFrame(animate);
      timer.update();
      const dt = timer.getDelta();
      mesh.rotation.x += 0.5 * st.speed * dt;
      mesh.rotation.y += 1.0 * st.speed * dt;
      renderer.render(scene, camera);
    }
    animate();

    const onResize = () => {
      const w2 = el.clientWidth;
      const h2 = el.clientHeight;
      camera.aspect = w2 / h2;
      camera.updateProjectionMatrix();
      renderer.setSize(w2, h2);
    };
    window.addEventListener('resize', onResize);

    return () => {
      cancelAnimationFrame(raf);
      window.removeEventListener('resize', onResize);
      renderer.dispose();
      geo.dispose();
      mat.dispose();
      el.removeChild(renderer.domElement);
    };
  }, []);

  useEffect(() => {
    const s = stateRef.current;
    if (!s) return;
    s.speed = params.rotSpeed;
    s.mesh.material.color.set(params.color);
    s.mesh.scale.setScalar(params.scale);

    const geoMap = {
      box: () => new BoxGeometry(1.4, 1.4, 1.4),
      sphere: () => new SphereGeometry(1, 32, 32),
      torus: () => new TorusGeometry(1, 0.4, 16, 48),
      knot: () => new TorusKnotGeometry(1, 0.35, 100, 16)
    };
    const makeFn = geoMap[params.shape] || geoMap.knot;
    const oldGeo = s.mesh.geometry;
    s.mesh.geometry = makeFn();
    oldGeo.dispose();
  }, [params.color, params.scale, params.shape, params.rotSpeed]);

  return <div ref={mountRef} className="flex-1" />;
}

