function App() {
  const { data, send } = useNodeRed();
  const params = data || { rotSpeed: 1, color: '#22d3ee', scale: 1, shape: 'knot' };

  return (
    <Page>
      <Header title="fromcubes 3D" subtitle="Three.js + live Node-RED data" />
      <ThreeCanvas params={params} />
      <StatusBar params={params} onShapeSelect={(s) => send({ shape: s })} />
    </Page>
  );
}
